worked_example.final_code:
import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;

public class OrderArchiver {
    public static void main(String[] args) throws IOException {
        Path base    = Path.of("orders");
        Path input   = base.resolve("input");
        Path backup  = base.resolve("backup");
        Path reports = base.resolve("reports");

        Files.createDirectories(input);
        Files.createDirectories(backup);
        Files.createDirectories(reports);

        Files.writeString(input.resolve("march.csv"),
            "ORD-001,Mouse,799\nORD-002,Keyboard,1999\nORD-003,USB Hub,499");
        Files.writeString(input.resolve("april.csv"),
            "ORD-004,Monitor,18999\nORD-005,Headphones,2999");
        Files.writeString(input.resolve("may.csv"),
            "ORD-006,Laptop Stand,1299\nORD-007,Webcam,4999\nORD-008,SSD,5999");

        List<String> reportLines = new ArrayList<>(Arrays.asList("Order Summary", "============="));

        try (Stream<Path> files = Files.list(input)) {
            files.filter(p -> p.toString().endsWith(".csv"))
                 .sorted()
                 .forEach(csv -> {
                     try {
                         List<String> lines = Files.readAllLines(csv);
                         long total = lines.stream()
                             .mapToLong(l -> Long.parseLong(l.split(",")[2])).sum();
                         String summary = csv.getFileName() + ": " + lines.size() + " orders, ₹" + total;
                         System.out.println(summary);
                         reportLines.add(summary);
                     } catch (IOException e) { throw new UncheckedIOException(e); }
                 });
        }

        Files.write(reports.resolve("summary.txt"), reportLines);
        System.out.println("Report saved.");

        try (Stream<Path> files = Files.list(input)) {
            files.filter(p -> p.toString().endsWith(".csv")).forEach(csv -> {
                try {
                    Files.move(csv, backup.resolve(csv.getFileName()),
                        StandardCopyOption.REPLACE_EXISTING);
                    System.out.println("Archived: " + csv.getFileName());
                } catch (IOException e) { throw new UncheckedIOException(e); }
            });
        }

        try (Stream<Path> backed = Files.list(backup)) {
            System.out.println("Backup: " + backed.count() + " files");
        }
    }
}

